import java.io.*;import java.util.*;class Main{static void tog(Set<String>s,String p){if(!s.add(p))s.remove(p);}static boolean cover(int[][]rs){long area=0;int minx=Integer.MAX_VALUE,miny=Integer.MAX_VALUE,maxx=Integer.MIN_VALUE,maxy=Integer.MIN_VALUE;Set<String>c=new HashSet<>();for(int[]r:rs){int x1=r[0],y1=r[1],x2=r[2],y2=r[3];minx=Math.min(minx,x1);miny=Math.min(miny,y1);maxx=Math.max(maxx,x2);maxy=Math.max(maxy,y2);area+=(long)(x2-x1)*(y2-y1);tog(c,x1+","+y1);tog(c,x1+","+y2);tog(c,x2+","+y1);tog(c,x2+","+y2);}Set<String>o=new HashSet<>(Arrays.asList(minx+","+miny,minx+","+maxy,maxx+","+miny,maxx+","+maxy));return area==(long)(maxx-minx)*(maxy-miny)&&c.equals(o);}public static void main(String[]a)throws Exception{String[]d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);int[][]rs=new int[n][4];for(int i=0;i<n;i++)for(int j=0;j<4;j++)rs[i][j]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(cover(rs)?"true":"false");}System.out.print(out);}}
